Function: "use strict";
const http = require("http");
const url = require("url");
const os = require("os");
const path = require("path");
const fs = require("fs");
const Queue = require("./queue");
const Processor = require("./processor");
const Monitor = require("./monitor");

const port = process.env.PORT || 8080;
const queue = new Queue();
const processor = new Processor(queue);
const monitor = new Monitor(processor);

processor.start();

// Flag is in /haystack/needle
const flagPath = path.join( "/", "haystack", "needle");

const server = http.createServer((req, res) => {
	req.on("data", () => {});
	req.on("end", () => {
		const path = url.parse(req.url).pathname;
		switch (path) {
			case "/process":
				queue.enqueue(req.headers["x-data"] || "default");
				res.writeHead(202);
				res.end("Accepted");
				break;
			case "/stats":
				res.writeHead(200, {"Content-Type": "application/json"});
				res.end(JSON.stringify(monitor.getStats()));
				break;
			case "/flag":
				if (os.loadavg()[0] < 1) {
					try {
						const flag = fs.readFileSync(flagPath, "utf8").trim();
						res.writeHead(200);
						res.end(flag);
					} catch (err) {
						res.writeHead(500);
						res.end("Error reading flag");
					}
				} else {
					res.writeHead(503);
					res.end("Server too busy");
				}
				break;
			default:
				res.writeHead(404);
				res.end("Not found");
				break;
		}
	});
});

server.listen(port, () => {
	console.log(`Server listening on port ${port}`);
});
